content:
{
  "sentences": [
    {
      "text": "公寓的客廳很大，可是冷氣壞掉了。",
      "pinyin": "Gōngyù de kètīng hěn dà, kěshì lěngqì huài diào le.",
      "pinyin_numeric": "gong1yu4 de5 ke4ting1 hen3 da4, ke3shi4 leng3qi4 huai4 diao4 le5.",
      "translation_en": "The apartment's living room is big, but the air conditioner is broken.",
      "translation_ko": "아파트 거실은 넓은데 에어컨이 고장 났어요."
    },
    {
      "text": "浴室的馬桶壞掉了，需要修理。",
      "pinyin": "Yùshì de mǎtǒng huài diào le, xūyào xiūlǐ.",
      "pinyin_numeric": "yu4shi4 de5 ma3tong3 huai4 diao4 le5, xu1yao4 xiu1li3.",
      "translation_en": "The toilet in the bathroom is broken and needs repair.",
      "translation_ko": "욕실의 변기가 고장 나서 수리가 필요해요."
    },
    {
      "text": "廚房的冰箱壞掉了，所以食物都壞了。",
      "pinyin": "Chúfáng de bīngxiāng huài diào le, suǒyǐ shíwù dōu huài le.",
      "pinyin_numeric": "chu2fang2 de5 bing1xiang1 huai4 diao4 le5, suo3yi3 shi2wu4 dou1 huai4 le5.",
      "translation_en": "The refrigerator in the kitchen is broken, so all the food has gone bad.",
      "translation_ko": "부엌의 냉장고가 고장 나서 음식이 다 상했어요."
    },
    {
      "text": "房間的燈壞掉了，晚上很暗。",
      "pinyin": "Fángjiān de dēng huài diào le, wǎnshàng hěn àn.",
      "pinyin_numeric": "fang2jian1 de5 deng1 huai4 diao4 le5, wan3shang4 hen3 an4.",
      "translation_en": "The light in the room is broken, so it's very dark at night.",
      "translation_ko": "방의 등이 고장 나서 밤에 매우 어두워요."
    },
    {
      "text": "陽台的窗戶壞掉了，風一直吹進來。",
      "pinyin": "Yángtái de chuānghù huài diào le, fēng yīzhí chuī jìnlái.",
      "pinyin_numeric": "yang2tai2 de5 chuang1hu4 huai4 diao4 le5, feng1 yi1zhi2 chui1 jin4lai2.",
      "translation_en": "The window on the balcony is broken, and the wind keeps blowing in.",
      "translation_ko": "발코니의 창문이 고장 나서 바람이 계속 들어와요."
    },
    {
      "text": "客廳的沙發壞掉了，坐起來不舒服。",
      "pinyin": "Kètīng de shāfā huài diào le, zuò qǐlái bù shūfú.",
      "pinyin_numeric": "ke4ting1 de5 sha1fa1 huai4 diao4 le5, zuo4 qi3lai2 bu4 shu1fu2.",
      "translation_en": "The sofa in the living room is broken, so it's uncomfortable to sit on.",
      "translation_ko": "거실의 소파가 고장 나서 앉기가 불편해요."
    },
    {
      "text": "洗衣機壞掉了，我必須用手洗衣服。",
      "pinyin": "Xǐyījī huài diào le, wǒ bìxū yòng shǒu xǐ yīfú.",
      "pinyin_numeric": "xi3yi1ji1 huai4 diao4 le5, wo3 bi4xu1 yong4 shou3 xi3 yi1fu2.",
      "translation_en": "The washing machine is broken, so I have to wash clothes by hand.",
      "translation_ko": "세탁기가 고장 나서 손으로 빨래를 해야 해요."
    },
    {
      "text": "房間的書桌壞掉了，我沒辦法做功課。",
      "pinyin": "Fángjiān de shūzhuō huài diào le, wǒ méi bànfǎ zuò gōngkè.",
      "pinyin_numeric": "fang2jian1 de5 shu1zhuo1 huai4 diao4 le5, wo3 mei2 ban4fa3 zuo4 gong1ke4.",
      "translation_en": "The desk in the room is broken, so I can't do my homework.",
      "translation_ko": "방의 책상이 고장 나서 숙제를 할 수 없어요."
    },
    {
      "text": "浴室的熱水器壞掉了，洗澡水是冷的。",
      "pinyin": "Yùshì de rèshuǐqì huài diào le, xǐzǎo shuǐ shì lěng de.",
      "pinyin_numeric": "yu4shi4 de5 re4shui3qi4 huai4 diao4 le5, xi3zao3 shui3 shi4 leng3 de5.",
      "translation_en": "The water heater in the bathroom is broken, so the shower water is cold.",
      "translation_ko": "욕실의 온수기가 고장 나서 샤워 물이 차가워요."
    },
    {
      "text": "廚房的門壞掉了，打不開。",
      "pinyin": "Chúfáng de mén huài diào le, dǎ bù kāi.",
      "pinyin_numeric": "chu2fang2 de5 men2 huai4 diao4 le5, da3 bu4 kai1.",
      "translation_en": "The kitchen door is broken and won't open.",
      "translation_ko": "부엌 문이 고장 나서 열리지 않아요."
    }
  ]
}
